-- Generated by kUML — schema for "LapisCloud"
-- Dialect: postgres

CREATE TABLE membership_tier (
    id UUID NOT NULL PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    description VARCHAR(1000) NOT NULL,
    contribution_amount DECIMAL(12, 2) NOT NULL,
    billing_interval VARCHAR(9) NOT NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    CHECK (billing_interval IN ('MONTHLY', 'QUARTERLY', 'YEARLY'))
);

CREATE TABLE document_folder (
    id UUID NOT NULL PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    parent_folder_id UUID NULL
);

-- V0.4.1 Serienbrief/PDF engine: the issuing association's own letterhead/bank/Gemeinnuetzigkeit
-- data. Exactly one row by convention (see 11-organization-settings.kuml.kts file header) --
-- seeded unconditionally below (not via DevSeedData, which is opt-in/demo-gated and must never
-- gate a real capability like letterhead data existing at all).
-- postal_mail_enabled (V0.4.2): explicit opt-in gate for Letterxpress postal-mail dispatch, see
-- that column's comment in 11-organization-settings.kuml.kts -- AVV requirement.
-- politician_ranking_enabled (V0.6.4): explicit opt-in gate for the Politiker-Profile/-Ranking
-- feature, see that column's comment in 11-organization-settings.kuml.kts.
CREATE TABLE organization_settings (
    id UUID NOT NULL PRIMARY KEY,
    name VARCHAR(300) NOT NULL,
    street VARCHAR(200) NULL,
    postal_code VARCHAR(20) NULL,
    city VARCHAR(200) NULL,
    country VARCHAR(100) NULL,
    bank_iban VARCHAR(34) NULL,
    bank_bic VARCHAR(11) NULL,
    tax_exemption_authority VARCHAR(300) NULL,
    tax_exemption_date DATE NULL,
    is_political_party BOOLEAN NOT NULL DEFAULT FALSE,
    postal_mail_enabled BOOLEAN NOT NULL DEFAULT FALSE,
    politician_ranking_enabled BOOLEAN NOT NULL DEFAULT FALSE
);

CREATE TABLE committee (
    id UUID NOT NULL PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    type VARCHAR(16) NOT NULL,
    description VARCHAR(1000) NOT NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    quorum_percent INTEGER NOT NULL DEFAULT 50,
    created_at TIMESTAMP NOT NULL,
    CHECK (type IN ('EXECUTIVE_BOARD', 'WORKING_GROUP', 'COMMISSION', 'OTHER', 'GENERAL_ASSEMBLY'))
);

CREATE TABLE cost_center (
    id UUID NOT NULL PRIMARY KEY,
    code VARCHAR(50) NOT NULL,
    name VARCHAR(200) NOT NULL,
    description VARCHAR(1000) NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE
);

-- V0.5.1 §25 PartG donor identity for a non-member donor (see 10-accounting.kuml.kts file header).
CREATE TABLE external_donor (
    id UUID NOT NULL PRIMARY KEY,
    display_name VARCHAR(300) NOT NULL,
    donor_category VARCHAR(41) NOT NULL,
    street VARCHAR(200) NULL,
    postal_code VARCHAR(20) NULL,
    city VARCHAR(200) NULL,
    country VARCHAR(100) NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    CHECK (donor_category IN (
        'GERMAN_NATURAL_PERSON', 'EU_NATURAL_PERSON', 'NON_EU_FOREIGN_NATURAL_PERSON',
        'GERMAN_COMPANY_OR_ORGANIZATION', 'PUBLIC_LAW_CORPORATION', 'OVER_25_PERCENT_STATE_OWNED_COMPANY',
        'OTHER_PARTY_OR_PARLIAMENTARY_GROUP_ENTITY', 'PROFESSIONAL_OR_TRADE_ASSOCIATION', 'ANONYMOUS'
    ))
);

CREATE TABLE ledger_account (
    id UUID NOT NULL PRIMARY KEY,
    account_number VARCHAR(10) NOT NULL,
    name VARCHAR(200) NOT NULL,
    account_class INTEGER NOT NULL,
    type VARCHAR(9) NOT NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    reserve_type VARCHAR(27) NULL,
    is_cash_register BOOLEAN NOT NULL DEFAULT FALSE,
    CHECK (type IN ('ASSET', 'LIABILITY', 'EQUITY', 'INCOME', 'EXPENSE')),
    CHECK (reserve_type IN ('PROJEKTRUECKLAGE', 'FREIE_RUECKLAGE', 'WIEDERBESCHAFFUNGSRUECKLAGE', 'BETRIEBSMITTELRUECKLAGE'))
);

CREATE TABLE member (
    id UUID NOT NULL PRIMARY KEY,
    display_name VARCHAR(200) NOT NULL,
    email VARCHAR(320) NOT NULL UNIQUE,
    status VARCHAR(11) NOT NULL,
    joined_at DATE NOT NULL,
    anonymized_at TIMESTAMP NULL,
    street VARCHAR(200) NULL,
    postal_code VARCHAR(20) NULL,
    city VARCHAR(200) NULL,
    country VARCHAR(100) NULL,
    date_of_birth DATE NULL,
    nationality VARCHAR(100) NULL,
    membership_tier_id UUID NULL,
    CHECK (status IN ('ANTRAG', 'AKTIV', 'GAST', 'AUSGETRETEN'))
);

CREATE TABLE account (
    id UUID NOT NULL PRIMARY KEY,
    password_hash VARCHAR(200) NULL,
    oidc_subject VARCHAR(200) NULL,
    role VARCHAR(9) NOT NULL,
    member_id UUID NOT NULL,
    CHECK (role IN ('MEMBER', 'BOARD', 'TREASURER', 'ADMIN'))
);

CREATE TABLE contribution (
    id UUID NOT NULL PRIMARY KEY,
    period_start DATE NOT NULL,
    period_end DATE NOT NULL,
    amount_due DECIMAL(12, 2) NOT NULL,
    status VARCHAR(7) NOT NULL,
    paid_at TIMESTAMP NULL,
    paid_amount DECIMAL(12, 2) NULL,
    note VARCHAR(1000) NULL,
    created_at TIMESTAMP NOT NULL,
    member_id UUID NOT NULL,
    membership_tier_id UUID NOT NULL,
    CHECK (status IN ('OPEN', 'PAID', 'WAIVED', 'OVERDUE'))
);

CREATE TABLE document (
    id UUID NOT NULL PRIMARY KEY,
    folder_id UUID NOT NULL,
    title VARCHAR(300) NOT NULL,
    current_version_id UUID NULL,
    created_by UUID NOT NULL,
    created_at TIMESTAMP NOT NULL,
    access_level VARCHAR(14) NOT NULL,
    is_deleted BOOLEAN NOT NULL DEFAULT FALSE,
    CHECK (access_level IN ('PUBLIC_MEMBERS', 'BOARD_ONLY', 'ADMIN_ONLY'))
);

CREATE TABLE mailing_list (
    id UUID NOT NULL PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    description VARCHAR(1000) NULL,
    created_by UUID NOT NULL
);

CREATE TABLE direct_message (
    id UUID NOT NULL PRIMARY KEY,
    body VARCHAR(10000) NOT NULL,
    sender_id UUID NOT NULL,
    recipient_id UUID NOT NULL,
    sent_at TIMESTAMP NOT NULL,
    read_at TIMESTAMP NULL
);

CREATE TABLE erasure_request (
    id UUID NOT NULL PRIMARY KEY,
    subject_member_id UUID NOT NULL,
    requested_at TIMESTAMP NOT NULL,
    requested_by UUID NOT NULL,
    reason VARCHAR(1000) NOT NULL,
    mode VARCHAR(31) NOT NULL,
    status VARCHAR(9) NOT NULL,
    decided_by UUID NULL,
    decided_at TIMESTAMP NULL,
    decision_note VARCHAR(1000) NULL,
    executed_at TIMESTAMP NULL,
    legal_hold BOOLEAN NOT NULL DEFAULT FALSE,
    outcome_summary TEXT NULL,
    CHECK (mode IN ('ANONYMIZE', 'HARD_DELETE_WHERE_UNCONSTRAINED')),
    CHECK (status IN ('REQUESTED', 'APPROVED', 'REJECTED', 'COMPLETED'))
);

CREATE TABLE committee_membership (
    id UUID NOT NULL PRIMARY KEY,
    role VARCHAR(12) NOT NULL,
    since DATE NOT NULL,
    until DATE NULL,
    committee_id UUID NOT NULL,
    member_id UUID NOT NULL,
    CHECK (role IN ('CHAIR', 'DEPUTY_CHAIR', 'SECRETARY', 'MEMBER', 'ASSESSOR'))
);

-- V0.6.1 Internes Crowdfunding: ltr_balance (a provisional balance SNAPSHOT, no ledger rows) is
-- replaced by ltr_ledger_entry, an append-only, signed-amount, per-member ledger -- see
-- 08-ltr-balance.kuml.kts file header for the full rationale. There was never a production
-- deployment of the pre-V0.6.1 schema, so this baseline is edited destructively (DROP + CREATE
-- inline) rather than adding a V2 migration -- consistent with this codebase's "V1__baseline.sql
-- is ONE consolidated migration" convention.
CREATE TABLE ltr_ledger_entry (
    id UUID NOT NULL PRIMARY KEY,
    entry_type VARCHAR(21) NOT NULL,
    amount_ltr DECIMAL(18, 2) NOT NULL,
    reference_type VARCHAR(20) NULL,
    reference_id UUID NULL,
    note VARCHAR(500) NULL,
    created_by UUID NULL,
    created_at TIMESTAMP NOT NULL,
    member_id UUID NOT NULL,
    CHECK (entry_type IN ('MINT', 'PROJECT_STAKE', 'PROJECT_STAKE_RELEASE', 'VOTE_STAKE', 'PEER_TRANSFER_OUT', 'PEER_TRANSFER_IN')),
    CHECK (reference_type IN ('CROWDFUNDING_PROJECT', 'VOTE', 'PEER_TRANSFER'))
);

CREATE TABLE journal_entry (
    id UUID NOT NULL PRIMARY KEY,
    entry_date DATE NOT NULL,
    description VARCHAR(500) NOT NULL,
    voucher_reference VARCHAR(100) NULL,
    created_by UUID NOT NULL,
    status VARCHAR(6) NOT NULL,
    posted_at TIMESTAMP NULL,
    created_at TIMESTAMP NOT NULL,
    donor_member_id UUID NULL,
    donor_category VARCHAR(41) NULL,
    external_donor_id UUID NULL,
    CHECK (status IN ('DRAFT', 'POSTED')),
    CHECK (donor_category IN (
        'GERMAN_NATURAL_PERSON', 'EU_NATURAL_PERSON', 'NON_EU_FOREIGN_NATURAL_PERSON',
        'GERMAN_COMPANY_OR_ORGANIZATION', 'PUBLIC_LAW_CORPORATION', 'OVER_25_PERCENT_STATE_OWNED_COMPANY',
        'OTHER_PARTY_OR_PARLIAMENTARY_GROUP_ENTITY', 'PROFESSIONAL_OR_TRADE_ASSOCIATION', 'ANONYMOUS'
    ))
);

CREATE TABLE document_version (
    id UUID NOT NULL PRIMARY KEY,
    version_number INTEGER NOT NULL,
    file_name VARCHAR(300) NOT NULL,
    mime_type VARCHAR(150) NOT NULL,
    file_size_bytes BIGINT NOT NULL,
    storage_key VARCHAR(300) NOT NULL,
    checksum_sha256 VARCHAR(64) NOT NULL,
    uploaded_by UUID NOT NULL,
    uploaded_at TIMESTAMP NOT NULL,
    change_note VARCHAR(1000) NULL,
    document_id UUID NOT NULL
