-- V0.4.2 Letterxpress postal-mail dispatch: one row per physical-letter dispatch attempt.
CREATE TABLE postal_delivery_log (
    id UUID NOT NULL PRIMARY KEY,
    document_reference VARCHAR(300) NOT NULL,
    dispatched_at TIMESTAMP NOT NULL,
    status VARCHAR(6) NOT NULL,
    provider_reference VARCHAR(200) NULL,
    error_message VARCHAR(1000) NULL,
    recipient_member_id UUID NOT NULL,
    CHECK (status IN ('QUEUED', 'SENT', 'FAILED'))
);

-- V0.5.2 Transparenzregister (§20 GwG) beneficial-owner reminders. board_membership is a
-- Transparenzregister-facing beneficial-owner roster, parallel to (not a replacement of)
-- committee_membership -- see 13-transparenzregister.kuml.kts file header.
CREATE TABLE board_membership (
    id UUID NOT NULL PRIMARY KEY,
    committee_role VARCHAR(12) NOT NULL,
    started_at DATE NOT NULL,
    ended_at DATE NULL,
    member_id UUID NOT NULL,
    CHECK (committee_role IN ('CHAIR', 'DEPUTY_CHAIR', 'SECRETARY', 'MEMBER', 'ASSESSOR'))
);

CREATE TABLE transparenzregister_reminder (
    id UUID NOT NULL PRIMARY KEY,
    triggered_at TIMESTAMP NOT NULL,
    committee_role VARCHAR(12) NOT NULL,
    change_type VARCHAR(6) NOT NULL,
    resolved BOOLEAN NOT NULL,
    resolved_at TIMESTAMP NULL,
    member_id UUID NOT NULL,
    resolved_by UUID NULL,
    CHECK (committee_role IN ('CHAIR', 'DEPUTY_CHAIR', 'SECRETARY', 'MEMBER', 'ASSESSOR')),
    CHECK (change_type IN ('JOINED', 'LEFT'))
);

-- V0.5.3 GoBD-Revisionssicherheit: hash-chained, append-only audit log (see
-- 14-audit-log.kuml.kts file header). audit_log_chain_state is a genesis-singleton row (exactly
-- one row, seeded below), mirroring organization_settings's own pattern -- a SELECT ... FOR UPDATE
-- on this one row is what serializes concurrent audit-log writers race-free, including for the
-- very first ("genesis") entry.
CREATE TABLE audit_log_chain_state (
    id UUID NOT NULL PRIMARY KEY,
    last_sequence_number BIGINT NOT NULL DEFAULT 0,
    last_entry_hash VARCHAR(64) NULL
);

CREATE TABLE audit_log_entry (
    id UUID NOT NULL PRIMARY KEY,
    sequence_number BIGINT NOT NULL,
    occurred_at TIMESTAMP NOT NULL,
    actor_member_id UUID NULL,
    actor_role VARCHAR(9) NULL,
    entity_type VARCHAR(22) NOT NULL,
    entity_id UUID NOT NULL,
    action VARCHAR(6) NOT NULL,
    before_snapshot TEXT NULL,
    after_snapshot TEXT NULL,
    entry_hash VARCHAR(64) NOT NULL,
    previous_entry_hash VARCHAR(64) NULL,
    CHECK (actor_role IN ('MEMBER', 'BOARD', 'TREASURER', 'ADMIN')),
    CHECK (entity_type IN ('JOURNAL_ENTRY', 'PARTY_DONATION_VERDICT', 'RESOLUTION', 'BOARD_MEMBERSHIP')),
    CHECK (action IN ('CREATE', 'UPDATE', 'POST'))
);

-- V0.5.4 Backup-/Restore-/Datenexport-Garantie: one row per completed (or failed) full-organization
-- export/restore attempt (see 15-backup-export.kuml.kts file header for why this is deliberately
-- NOT part of the GoBD hash chain above).
CREATE TABLE backup_operation_log (
    id UUID NOT NULL PRIMARY KEY,
    operation_type VARCHAR(7) NOT NULL,
    status VARCHAR(9) NOT NULL,
    started_at TIMESTAMP NOT NULL,
    finished_at TIMESTAMP NOT NULL,
    bundle_format_version INT NOT NULL,
    table_count INT NOT NULL,
    total_row_count BIGINT NOT NULL,
    blob_count INT NOT NULL,
    blob_bytes_total BIGINT NOT NULL,
    bundle_size_bytes BIGINT NOT NULL,
    error_message VARCHAR(2000) NULL,
    actor_member_id UUID NOT NULL,
    CHECK (operation_type IN ('EXPORT', 'RESTORE')),
    CHECK (status IN ('SUCCEEDED', 'FAILED'))
);

-- V0.5.5 DSGVO-Vollausbau: AVV-Register/TOMs/DSFA-Vorlage/Datenpannenmeldung (see
-- 16-dsgvo-compliance.kuml.kts file header for the full domain rationale and legal-verification
-- disclaimer). Documentation-/workflow-tool support for a human-made legal decision -- avv_status,
-- dpia_required, authority_notification_required are always human input, never computed.
CREATE TABLE processing_agreement (
    id UUID NOT NULL PRIMARY KEY,
    processor_name VARCHAR(300) NOT NULL,
    processing_purpose TEXT NOT NULL,
    data_categories VARCHAR(2000) NOT NULL,
    avv_status VARCHAR(6) NOT NULL,
    signed_date DATE NULL,
    review_due_date DATE NULL,
    document_id UUID NULL,
    notes VARCHAR(2000) NULL,
    created_at TIMESTAMP NOT NULL,
    created_by UUID NOT NULL,
    updated_at TIMESTAMP NULL,
    updated_by UUID NULL,
    CHECK (avv_status IN ('NONE', 'DRAFT', 'SIGNED'))
);

CREATE TABLE technical_organizational_measure (
    id UUID NOT NULL PRIMARY KEY,
    category VARCHAR(23) NOT NULL,
    title VARCHAR(300) NOT NULL,
    description TEXT NOT NULL,
    version INT NOT NULL DEFAULT 1,
    created_at TIMESTAMP NOT NULL,
    created_by UUID NOT NULL,
    updated_at TIMESTAMP NULL,
    updated_by UUID NULL,
    CHECK (
        category IN (
            'PHYSICAL_ACCESS_CONTROL', 'SYSTEM_ACCESS_CONTROL', 'DATA_ACCESS_CONTROL', 'TRANSFER_CONTROL',
            'INPUT_CONTROL', 'ORDER_CONTROL', 'AVAILABILITY_CONTROL', 'SEPARATION_CONTROL'
        )
    )
);

CREATE TABLE data_protection_impact_assessment (
    id UUID NOT NULL PRIMARY KEY,
    title VARCHAR(300) NOT NULL,
    processing_description TEXT NOT NULL,
    necessity_proportionality TEXT NULL,
    risk_likelihood VARCHAR(6) NULL,
    risk_severity VARCHAR(6) NULL,
    risk_assessment TEXT NULL,
    mitigation_measures TEXT NULL,
    dpia_required BOOLEAN NULL,
    outcome_rationale TEXT NULL,
    status VARCHAR(19) NOT NULL,
    version INT NOT NULL DEFAULT 1,
    created_at TIMESTAMP NOT NULL,
    created_by UUID NOT NULL,
    updated_at TIMESTAMP NULL,
    updated_by UUID NULL,
    CHECK (risk_likelihood IN ('LOW', 'MEDIUM', 'HIGH')),
    CHECK (risk_severity IN ('LOW', 'MEDIUM', 'HIGH')),
    CHECK (status IN ('DRAFT', 'COMPLETED', 'OUTDATED_REVIEW_DUE'))
);

CREATE TABLE data_breach_incident (
    id UUID NOT NULL PRIMARY KEY,
    discovered_at TIMESTAMP NOT NULL,
    description TEXT NOT NULL,
    affected_data_categories VARCHAR(2000) NOT NULL,
    estimated_affected_persons INT NULL,
    risk_assessment TEXT NULL,
    risk_level VARCHAR(6) NULL,
    authority_notification_required BOOLEAN NULL,
    authority_notified_at TIMESTAMP NULL,
    data_subjects_notified_at TIMESTAMP NULL,
    status VARCHAR(24) NOT NULL,
    reported_at TIMESTAMP NOT NULL,
    reported_by UUID NOT NULL,
    updated_at TIMESTAMP NULL,
    updated_by UUID NULL,
    CHECK (risk_level IN ('LOW', 'MEDIUM', 'HIGH')),
    CHECK (status IN ('REPORTED', 'UNDER_ASSESSMENT', 'NOTIFIED_AUTHORITY', 'NO_NOTIFICATION_REQUIRED', 'CLOSED'))
);

-- V0.6.1 Internes Crowdfunding (see 17-crowdfunding.kuml.kts file header for the full fachlich
-- model). crowdfunding_submission_gate is a genesis-singleton lock row, mirroring
-- organization_settings/audit_log_chain_state's own pattern -- seeded below.
CREATE TABLE crowdfunding_project (
    id UUID NOT NULL PRIMARY KEY,
    title VARCHAR(200) NOT NULL,
    description VARCHAR(4000) NOT NULL,
    submitter_member_id UUID NOT NULL,
    initial_weight_ltr DECIMAL(18, 2) NOT NULL,
    status VARCHAR(8) NOT NULL,
    rejection_reason VARCHAR(2000) NULL,
    reviewed_by UUID NULL,
    reviewed_at TIMESTAMP NULL,
    submitted_at TIMESTAMP NOT NULL,
    CHECK (status IN ('PENDING', 'APPROVED', 'REJECTED'))
);

CREATE TABLE crowdfunding_reaction (
    id UUID NOT NULL PRIMARY KEY,
    project_id UUID NOT NULL,
    reaction_value VARCHAR(7) NOT NULL,
    cast_at TIMESTAMP NOT NULL,
    member_id UUID NOT NULL,
    CHECK (reaction_value IN ('LIKE', 'DISLIKE'))
);

CREATE TABLE crowdfunding_distribution (
    id UUID NOT NULL PRIMARY KEY,
    project_id UUID NOT NULL,
    period_start DATE NOT NULL,
    period_end DATE NOT NULL,
    basket_total_at_distribution INT NOT NULL,
    amount_eur DECIMAL(12, 2) NOT NULL,
    computed_at TIMESTAMP NOT NULL,
    triggered_by UUID NOT NULL
);

CREATE TABLE crowdfunding_submission_gate (
    id UUID NOT NULL PRIMARY KEY
);

-- V0.6.3 direkte LTR-Peer-to-Peer-Uebertragung (see 18-peer-transfer.kuml.kts file header for the
-- full fachlich model). Split from ltr_ledger_entry: this table carries the fachlich detail
-- (self-reported characterization, optional purpose), ltr_ledger_entry carries only the generic
-- signed booking effect (PEER_TRANSFER_OUT/PEER_TRANSFER_IN, referenceType=PEER_TRANSFER).
CREATE TABLE peer_transfer (
    id UUID NOT NULL PRIMARY KEY,
    amount_ltr DECIMAL(18, 2) NOT NULL,
    characterization VARCHAR(13) NOT NULL,
    purpose VARCHAR(500) NULL,
    sender_member_id UUID NOT NULL,
    recipient_member_id UUID NOT NULL,
    initiated_by UUID NULL,
    created_at TIMESTAMP NOT NULL,
    CHECK (characterization IN ('SCHENKUNG', 'HONORAR', 'PRIVATVERKAUF', 'SONSTIGES'))
);

-- V0.6.5 Price-Oracle fuer die Anker-Bindung (see 19-price-oracle.kuml.kts file header for the
-- full fachlich model). price_oracle_config is a single-row, ADMIN-tunable policy row, seeded
-- below, mirroring organization_settings/crowdfunding_submission_gate's own pattern -- no FK to
-- member. price_oracle_conversion is the permanent per-conversion provenance record; ltr_ledger_
-- entry_id is deliberately a plain, non-FK column (same polymorphic-pointer idiom
-- ltr_ledger_entry.reference_id already uses).
CREATE TABLE price_oracle_config (
    id UUID NOT NULL PRIMARY KEY,
    anchor_asset VARCHAR(11) NOT NULL,
    donation_currency VARCHAR(3) NOT NULL,
    anchor_units_per_ltr DECIMAL(38, 18) NOT NULL,
    cache_ttl_seconds INT NOT NULL,
    min_quorum INT NOT NULL,
    outlier_threshold_bps INT NOT NULL,
    max_spread_bps INT NOT NULL,
    updated_at TIMESTAMP NOT NULL,
    CHECK (anchor_asset IN ('BITCOIN_BTC', 'GOLD_XAU', 'FIAT'))
);

CREATE TABLE price_oracle_conversion (
    id UUID NOT NULL PRIMARY KEY,
    donation_amount DECIMAL(18, 2) NOT NULL,
    donation_currency VARCHAR(3) NOT NULL,
    anchor_asset VARCHAR(11) NOT NULL,
    anchor_price DECIMAL(38, 18) NOT NULL,
    anchor_units_per_ltr DECIMAL(38, 18) NOT NULL,
    ltr_minted DECIMAL(18, 2) NOT NULL,
    price_status VARCHAR(8) NOT NULL,
    source_count INT NOT NULL,
    sources_used VARCHAR(500) NOT NULL,
    price_timestamp TIMESTAMP NOT NULL,
    ltr_ledger_entry_id UUID NOT NULL,
    created_by UUID NULL,
    created_at TIMESTAMP NOT NULL,
    member_id UUID NOT NULL,
    CHECK (anchor_asset IN ('BITCOIN_BTC', 'GOLD_XAU', 'FIAT')),
    CHECK (price_status IN ('LIVE', 'DEGRADED', 'CACHED', 'DEFERRED'))
);

-- V0.6.4 Politiker-Profile und Politiker-Ranking (see 20-politician.kuml.kts file header for the
-- full fachlich model; renumbered from 19-politician.kuml.kts to 20 when merged onto master
-- alongside V0.6.5, which independently claimed the same next-free slot 19 off the same V0.6.3
-- base -- no functional change from the rename). Re-grant after revocation reactivates the same
-- politician_profile row (member_id UNIQUE below) rather than inserting a second one.
CREATE TABLE politician_profile (
    id UUID NOT NULL PRIMARY KEY,
    member_id UUID NOT NULL,
    status VARCHAR(6) NOT NULL,
    mandate_text VARCHAR(2000) NULL,
    granted_at TIMESTAMP NOT NULL,
    granted_by_member_id UUID NOT NULL,
    revoked_at TIMESTAMP NULL,
    revoked_by_member_id UUID NULL,
    CHECK (status IN ('ACTIVE', 'FORMER'))
);

CREATE TABLE politician_reaction (
    id UUID NOT NULL PRIMARY KEY,
    politician_profile_id UUID NOT NULL,
    reaction_value VARCHAR(7) NOT NULL,
    cast_at TIMESTAMP NOT NULL,
    rater_member_id UUID NOT NULL,
    CHECK (reaction_value IN ('LIKE', 'DISLIKE'))
);

CREATE TABLE politician_weight_snapshot (
    id UUID NOT NULL PRIMARY KEY,
    politician_profile_id UUID NOT NULL,
    period_month DATE NOT NULL,
    member_trust_weight DECIMAL(18, 2) NOT NULL,
    member_like_count INT NOT NULL,
    member_dislike_count INT NOT NULL,
    computed_at TIMESTAMP NOT NULL,
    computed_by_member_id UUID NOT NULL
);

