-- V0.4.1 Serienbrief/PDF engine: exactly one organization_settings row must exist from first
-- migration onward, in every environment (not just LAPIS_SEED_DEMO_DATA=true demo deployments) --
-- unlike every other row in this codebase, letterhead data existing at all is a real capability
-- precondition, not sample/demo data, so it is seeded here directly rather than via DevSeedData.
-- Fixed sentinel id, mirrors DevSeedData's own '...-0000-0000000000f1' (standardTierId) pattern.
-- ADMIN can (and should) overwrite every field via updateOrganizationSettings afterward.
INSERT INTO organization_settings (id, name)
VALUES ('00000000-0000-0000-0000-0000000000f2', 'Verein/Partei (bitte in Organisationseinstellungen konfigurieren)');

-- V0.5.3 GoBD-Revisionssicherheit: exactly one audit_log_chain_state row must exist from first
-- migration onward -- the genesis-singleton row AuditLogRecorder locks (SELECT ... FOR UPDATE) to
-- serialize concurrent audit-log writers and assign gapless sequence numbers, including for the
-- very first entry. Fixed sentinel id, next unused '...-0000-0000000000fN' slot after
-- organization_settings's own '...-f2'. last_entry_hash starts NULL (no entry written yet).
INSERT INTO audit_log_chain_state (id, last_sequence_number, last_entry_hash)
VALUES ('00000000-0000-0000-0000-0000000000f3', 0, NULL);

-- V0.6.1 Internes Crowdfunding: exactly one crowdfunding_submission_gate row must exist from
-- first migration onward -- the genesis-singleton row CrowdfundingService.submitProject locks
-- (SELECT ... FOR UPDATE) to serialize concurrent project submissions against the same decaying
-- top-weight entry hurdle. Fixed sentinel id, next unused '...-0000-0000000000fN' slot after
-- audit_log_chain_state's own '...-f3'. No other columns -- see 17-crowdfunding.kuml.kts file
-- header. Also registered in OrganizationRestoreService.SEEDED_SINGLETON_ROWS so a fresh restore
-- target is not mistaken for "already holds data".
INSERT INTO crowdfunding_submission_gate (id)
VALUES ('00000000-0000-0000-0000-0000000000f4');

-- V0.6.5 Price-Oracle fuer die Anker-Bindung: exactly one price_oracle_config row must exist from
-- first migration onward -- ADMIN can (and should) retune every field via updateOracleConfig
-- afterward. Fixed sentinel id, next unused '...-0000-0000000000fN' slot after
-- crowdfunding_submission_gate's own '...-f4'. Seeded defaults: BITCOIN_BTC anchor, EUR donation
-- currency, a placeholder peg (1 LTR = 0.000001 BTC), 300s cache TTL, quorum 2 (of 3 configured
-- BTC sources), 3% (300bps) outlier-rejection threshold, 10% (1000bps) max survivor spread before
-- halting. See 19-price-oracle.kuml.kts file header. Also registered in
-- OrganizationRestoreService.SEEDED_SINGLETON_ROWS so a fresh restore target is not mistaken for
-- "already holds data".
INSERT INTO price_oracle_config
    (id, anchor_asset, donation_currency, anchor_units_per_ltr,
     cache_ttl_seconds, min_quorum, outlier_threshold_bps, max_spread_bps, updated_at)
VALUES ('00000000-0000-0000-0000-0000000000f5', 'BITCOIN_BTC', 'EUR', 0.000001,
    300, 2, 300, 1000, CURRENT_TIMESTAMP);

